// auth.ts
async function processRequest(req: Request) {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    throw new Error('Missing authorization token');
  }

  const session = await redis.get(`session:${token}`);

  if (!session) {
    throw new Error('Invalid or expired session');
  }

  let user: User;
  try {
    user = JSON.parse(session);
  } catch (error) {
    throw new Error('Corrupted session data');
  }

  if (!user || typeof user !== 'object') {
    throw new Error('Invalid user data in session');
  }

  return getUserProfile(user);
}

// profile.ts
function getUserProfile(user: User) {
  if (!user.email || !user.name) {
    throw new Error('Incomplete user profile data');
  }

  return {
    name: user.name,
    email: user.email,
    avatar: user.avatar || '/default.png'
  };
}
```

**What was happening:**
- Redis sessions expire or get evicted
- `redis.get()` returns `null` for missing keys
- `JSON.parse(null)` returns `undefined`
- Accessing properties on `undefined` throws TypeError

**The fix:**
1. Validate token exists
2. Check session exists before parsing
3. Handle JSON parsing errors
4. Validate user object structure
5. Explicit error messages for debugging

This turns silent failures into proper 401/400 responses instead of 500s.

